import React from 'react';
import {
  Bar,
  BarChart,
  CartesianGrid,
  Cell,
  Legend,
  Line,
  LineChart,
  Pie,
  PieChart,
  ResponsiveContainer,
  Tooltip,
  XAxis,
  YAxis,
} from 'recharts';
import { formatVnd } from '../../../utils/formatters';
import reportStyles from '../../../styles/erpReportPage.module.css';

export type ChartKind = 'bar' | 'line' | 'pie';

const PIE_COLORS = ['#1677ff', '#fa8c16', '#52c41a', '#eb2f96', '#722ed1'];

export type ChartSeries = {
  dataKey: string;
  name: string;
  color: string;
};

type Props = {
  title: string;
  chartKind: ChartKind;
  data: Record<string, string | number>[];
  xKey?: string;
  series: ChartSeries[];
  pieData?: { name: string; value: number; color: string }[];
  testId: string;
};

const FinancialOverviewChart: React.FC<Props> = ({
  title,
  chartKind,
  data,
  xKey = 'name',
  series,
  pieData,
  testId,
}) => (
  <div className={reportStyles.chartCard} data-testid={testId}>
    <div className={reportStyles.chartCardHeader}>
      <h3 className={reportStyles.chartTitle}>{title}</h3>
    </div>
    <ResponsiveContainer width="100%" height={300}>
      {chartKind === 'pie' && pieData && pieData.length > 0 ? (
        <PieChart>
          <Pie data={pieData} dataKey="value" nameKey="name" cx="50%" cy="50%" outerRadius={100} label>
            {pieData.map((entry, index) => (
              <Cell key={entry.name} fill={entry.color ?? PIE_COLORS[index % PIE_COLORS.length]} />
            ))}
          </Pie>
          <Tooltip formatter={(v: number) => formatVnd(v)} />
          <Legend />
        </PieChart>
      ) : chartKind === 'line' ? (
        <LineChart data={data}>
          <CartesianGrid strokeDasharray="3 3" />
          <XAxis dataKey={xKey} />
          <YAxis tickFormatter={v => `${(Number(v) / 1e9).toFixed(1)}B`} />
          <Tooltip formatter={(v: number) => formatVnd(v)} />
          <Legend />
          {series.map(s => (
            <Line key={s.dataKey} type="monotone" dataKey={s.dataKey} name={s.name} stroke={s.color} strokeWidth={2} />
          ))}
        </LineChart>
      ) : (
        <BarChart data={data}>
          <CartesianGrid strokeDasharray="3 3" />
          <XAxis dataKey={xKey} />
          <YAxis tickFormatter={v => `${(Number(v) / 1e9).toFixed(1)}B`} />
          <Tooltip formatter={(v: number) => formatVnd(v)} />
          <Legend />
          {series.map(s => (
            <Bar key={s.dataKey} dataKey={s.dataKey} name={s.name} fill={s.color} />
          ))}
        </BarChart>
      )}
    </ResponsiveContainer>
  </div>
);

export default FinancialOverviewChart;
